  ('social-worker-moex-02315', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作方法的分類，下列何者將不會是未來的趨勢？', '["個案、團體、社區漸趨整合", "面對案主時，專業能力愈趨去脈絡化", "直接服務與間接服務的合作", "專科化證照帶來更精深的專業能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
